import{_ as t,o as r,c as s,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Spécifications Bannières","description":"","frontmatter":{"title":"Spécifications Bannières"},"headers":[],"relativePath":"docs/fr/advertisers/display-email/specs.md","filePath":"docs/fr/advertisers/display-email/specs.md"}'),i={name:"docs/fr/advertisers/display-email/specs.md"};function n(o,e,l,d,p,c){return r(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="specifications-bannieres" tabindex="-1">Spécifications Bannières <a class="header-anchor" href="#specifications-bannieres" aria-label="Permalink to &quot;Spécifications Bannières&quot;">​</a></h1><p>Pour garantir un affichage optimal sur tous les clients mails (Outlook, Gmail, Apple Mail...), merci de respecter ces standards IAB.</p><hr class="my-6"><h2 class="text-blue-200 mb-4">Formats Standards</h2><p>Les formats dépendent de l&#39;emplacement négocié dans la newsletter du partenaire.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Dimensions (L x H)</th><th style="text-align:left;">Usage fréquent</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Bannière Large</strong><br><span class="text-grey-dk-000 fs-2">(Leaderboard)</span></td><td style="text-align:left;"><strong>600 x 150 px</strong><br>(parfois 640px de large)</td><td style="text-align:left;">Header ou Cœur de mail.<br><em>Format le plus impactant.</em></td></tr><tr><td style="text-align:left;"><strong>Pavé</strong><br><span class="text-grey-dk-000 fs-2">(Rectangle)</span></td><td style="text-align:left;"><strong>300 x 250 px</strong></td><td style="text-align:left;">Colonne latérale ou fin de mail.<br><em>Format compact.</em></td></tr></tbody></table><br><h2 class="text-blue-200 mb-4">Contraintes Techniques</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;margin-bottom:40px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background-color:var(--vp-c-bg-elv);"><h3 class="mt-0 fs-4">📁 Fichiers</h3><ul class="mb-0"><li class="mb-2"><strong>Type :</strong> JPG, PNG ou GIF.</li><li class="mb-2"><strong>Couleurs :</strong> RVB.</li><li><strong>Poids :</strong> Max <strong>150 Ko</strong>.<br><em class="text-grey-dk-000">Recommandé &lt; 80 Ko pour un chargement rapide sur mobile.</em></li></ul></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background-color:var(--vp-c-bg-elv);"><h3 class="mt-0 fs-4">🎬 GIF Animés</h3><p class="mb-2">Acceptés, mais attention à <strong>Outlook</strong> (versions bureau) qui n&#39;affiche que la première image.</p><div style="background:var(--gi-tint-yellow-bg);border:1px solid var(--gi-tint-yellow-bg);padding:10px;border-radius:4px;color:var(--gi-tint-yellow-text);font-size:0.9em;"><strong>Règle d&#39;or :</strong> L&#39;information principale et le Call-to-Action doivent figurer sur la <strong>première frame</strong>. </div></div></div><h2 class="text-grey-dk-000 mb-4">💡 Bonnes Pratiques Design</h2><div style="border-left:4px solid var(--gi-accent);background:var(--gi-tint-blue-bg);padding:20px;border-radius:0 8px 8px 0;margin-bottom:20px;"><h3 class="mt-0 text-purple-200">La Bordure (Border)</h3><p>Si votre bannière a un fond blanc, elle risque de se fondre dans le fond de l&#39;email et de devenir invisible.</p><p class="mb-0">👉 <strong>Ajoutez une fine bordure grise de 1px</strong> (<code>#cccccc</code>) tout autour de votre créa pour bien la délimiter.</p></div><div style="border-left:4px solid var(--gi-tint-green-text);background:var(--gi-tint-green-bg);padding:20px;border-radius:0 8px 8px 0;"><h3 class="mt-0 text-green-200">Lisibilité Mobile</h3><p class="mb-0">Sur mobile, votre bannière de 600px sera réduite à ~350px de large. Évitez les polices trop fines ou trop petites (minimum 16px recommandé).</p></div>',12)])])}const u=t(i,[["render",n]]);export{m as __pageData,u as default};
